// SetSize updates the pane dimensions and rebuilds the viewport content.
func (p *AuditPane) SetSize(w, h int) {
	p.width = w
	// Reserve 1 line for the header divider.
	bodyH := h - 1
	if bodyH < 0 {
		bodyH = 0
	}
	p.height = h
	p.viewport.Width = w
	p.viewport.Height = bodyH
	body := p.renderBody()
	lines := strings.Count(body, "\n") + 1
	p.viewport.SetContent(body)
	p.viewport.GotoBottom()
	debugAudit("SetSize w=%d h=%d bodyH=%d events=%d bodyLines=%d vpOffset=%d",
		w, h, bodyH, len(p.events), lines, p.viewport.YOffset)
}

// SetEvents replaces the event list and refreshes the viewport.
func (p *AuditPane) SetEvents(events []AuditEventDisplay) {
	p.events = events
	body := p.renderBody()
	lines := strings.Count(body, "\n") + 1
	p.viewport.SetContent(body)
	p.viewport.GotoBottom()
	debugAudit("SetEvents events=%d bodyLines=%d vpW=%d vpH=%d vpOffset=%d",
		len(events), lines, p.viewport.Width, p.viewport.Height, p.viewport.YOffset)
}

